"use client"
import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import styles from './signup.module.css'; 

export default function SignupPage() {
  const router = useRouter();

  const [formData, setFormData] = useState({
    email: '',
    password: '',
    name: '',
    nickName: '',
    gender: 'MAN',
    address: ''
  });
  
  // 에러 메시지를 담을 상태
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
    // 사용자가 다시 입력하면 해당 필드의 에러 메시지 삭제
    if (errors[name]) {
      setErrors({ ...errors, [name]: '' });
    }
  };

  const handleSubmit = async (e: any) => {
    e.preventDefault();
    setErrors({}); // 초기화

    // 프론트엔드 1차 검사 (필수값 체크)
    // if (!formData.email || !formData.password || !formData.name || !formData.nickName) {
    //   console.error("Signup Error:", errors);
    //   alert("모든 필수 항목(닉네임 포함)을 입력해주세요.");
    //   return;
    // }

    try {
      const response = await fetch('http://localhost:8080/api/member/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        alert("회원가입이 성공적으로 완료되었습니다! 🎉");
        router.push('/main');
      } else {
        // 백엔드에서 보낸 에러 JSON 받기
        const errorData = await response.json();
        // 상태 업데이트 -> 화면 리렌더링 -> 빨간 글씨 표시
        console.log("백엔드에서 받은 에러 데이터:", errorData);
        setErrors(errorData);
      }
    } catch (error) {
      console.error("Signup Error:", error);
      alert("서버와 통신 중 오류가 발생했습니다.");
    }
  };

  return (
    <div className={styles.container}>
      <h2 className={styles.title}>회원가입</h2>
      
      <form onSubmit={handleSubmit} className={styles.form}>
        
        {/* 이메일 */}
        <div>
          <label className={styles.label}>이메일</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            placeholder="example@email.com"
            className={styles.input}
          />
          {/* ⭐️ ? */}
          {errors.email && <span className={styles.errorText}>{errors.email}</span>}
          
        </div>

        {/* 비밀번호 */}
        <div>
          <label className={styles.label}>비밀번호</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleChange}
            placeholder="비밀번호를 입력하세요"
            className={styles.input}
          />
          {/* ⭐️ 비밀번호 에러 표시 */}
          {errors.password && <span className={styles.errorText}>{errors.password}</span>}
          
        </div>

        {/* 이름 */}
        <div>
          <label className={styles.label}>이름</label>
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder="홍길동"
            className={styles.input}
          />
          {/* ⭐️ 이름 에러 표시 */}
          {errors.name && <span className={styles.errorText}>{errors.name}</span>}
          
        </div>

        {/* 닉네임 */}
        <div>
          <label className={styles.label}>닉네임</label>
          <input
            type="text"
            name="nickName"
            value={formData.nickName}
            onChange={handleChange}
            placeholder="별명을 입력하세요"
            className={styles.input}
          />
          {/* ⭐️ 닉네임 에러 표시 (가장 중요) */}
          {errors.nickName && <span className={styles.errorText}>{errors.nickName}</span>}
        </div>

        {/* 성별 */}
        <div>
          <label className={styles.label}>성별</label>
          <select name="gender"value={formData.gender} onChange={handleChange} className={styles.select}>
            <option value="MAN">남성</option>
            <option value="WOMAN">여성</option>
          </select>
        </div>

        {/* 주소 */}
        <div>
          <label className={styles.label}>주소</label>
          <input
            type="text"
            name="address"
            value={formData.address}
            onChange={handleChange}
            placeholder="주소를 입력하세요"
            className={styles.input}
          />
          {errors.address && <span className={styles.errorText}>{errors.address}</span>}
        </div>

        {/* 가입 버튼 */}
        <button type="submit" className={styles.button}>
          가입하기
        </button>

      </form>
    </div>
  );
}